// source: swagger
// endpoint: POST /account-service/ee/ads/activity/get
// summary: 获取活动广告（需登录后 cookie，匿名请求返回 body.status=400）
// generated by tp api pull

import { test, expect } from '@playwright/test';

const BASE_URL = process.env.CAMELTV_BASE_URL || 'http://localhost:8000';

test.describe('POST /account-service/ee/ads/activity/get', () => {
  test.describe.configure({ retries: 2 });

  test('API-TC-ADS-POST-001: 正向请求 — 合法参数', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/ee/ads/activity/get`,
      { data: { "displayPlatform": "PC" } }
    );
    // API 始终返回 HTTP 200；需登录 cookie 否则 body.status=400
    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body).toHaveProperty('status');
  });

  test('API-TC-ADS-POST-002: 入参校验 — 缺少必填参数', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/ee/ads/activity/get`
    );
    // API 始终返回 HTTP 200；缺少 body 时 body.status=400
    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body.status).toBe(400);
  });

  test('API-TC-ADS-POST-003: 入参校验 — 非法参数值', async ({ request }) => {
    const response = await request.post(
      `${BASE_URL}/account-service/ee/ads/activity/get`,
      { data: { displayPlatform: "' OR '1'='1" } }
    );
    // API 始终返回 HTTP 200
    expect(response.status()).toBe(200);
  });
});
